SourceCode.Declaration:
/// <summary>
/// Service class for fleet vehicle operations.
/// </summary>
public class FmVehicleService
{
    FmVehicle vehicle;
}

Method.Source:
public void run()
{
    FmVehicle v;
    select firstOnly v
        where v.VIN != '';
    Info(strFmt("@Fleet:Found", v.RecId));
}

public static FmVehicleService construct()
{
    return new FmVehicleService();
}
